async (params, browser) => {
  // Open page
  await browser.open('https://app.todoist.com/app/activity/completed')

  // Wait for content
  await browser.waitForSelector('main, [class*="productivity"], .content', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const stats = {}; document.querySelectorAll('[class*="stat"], [class*="Stat"], .karma-summary span, dt, dd').forEach(el => { const text = el.textContent.trim(); if(text.length<50) { const parts = text.split(':'); if(parts.length===2) stats[parts[0].trim().toLowerCase()]=parts[1].trim(); } }); const allText = document.body.innerText; const karma = allText.match(/karma[:\s]+(\d[\d,]*)/i)?.[1]||''; const completed = allText.match(/(\d[\d,]*)\s*completed/i)?.[1]||''; return { karma, tasks_completed: completed, stats, url: window.location.href }`)

  return page_data
}
